-- DDL Example: Manage table structure

-- CREATE: Define a new table
CREATE TABLE categories (
  id INT PRIMARY KEY,
  name VARCHAR(50) NOT NULL
);

-- INSERT some data to work with
INSERT INTO categories VALUES (1,'Electronics'),(2,'Books'),(3,'Clothing');

SELECT * FROM categories;

-- ALTER: Add a new column
ALTER TABLE categories ADD COLUMN description VARCHAR(200);

-- ALTER: Rename a column (standard SQL / PostgreSQL)
ALTER TABLE categories RENAME COLUMN description TO notes;

SELECT * FROM categories;

-- DROP: Remove the table entirely
-- DROP TABLE categories;

CREATE TABLE tasks (
  id INT PRIMARY KEY,
  title VARCHAR(100),
  status VARCHAR(20) DEFAULT 'todo',
  priority INT
);

-- INSERT: Add new rows
INSERT INTO tasks VALUES
  (1, 'Design database schema', 'todo',        1),
  (2, 'Write SQL queries',      'in_progress',  2),
  (3, 'Review pull request',    'todo',         3),
  (4, 'Deploy to staging',      'blocked',      1),
  (5, 'Write unit tests',       'todo',         2);

-- SELECT: Read data
SELECT * FROM tasks ORDER BY priority;

-- UPDATE: Modify existing rows
UPDATE tasks SET status = 'done' WHERE id = 2;
UPDATE tasks SET priority = priority + 1 WHERE status = 'todo';

SELECT * FROM tasks ORDER BY priority;

-- DELETE: Remove rows (with WHERE to avoid deleting all)
DELETE FROM tasks WHERE status = 'done';

SELECT * FROM tasks ORDER BY id;

CREATE TABLE orders (
  id INT PRIMARY KEY,
  customer VARCHAR(50),
  total DECIMAL(8,2),
  status VARCHAR(20) DEFAULT 'new'
);

INSERT INTO orders VALUES
  (1, 'Alice', 150.00, 'new'),
  (2, 'Bob',   200.00, 'new'),
  (3, 'Carol',  80.00, 'new');

SELECT * FROM orders;

-- TCL: SAVEPOINT lets you partially rollback
BEGIN;
  UPDATE orders SET status = 'processing' WHERE id = 1;
  SAVEPOINT after_order_1;
  UPDATE orders SET status = 'processing' WHERE id = 2;
  SAVEPOINT after_order_2;
  UPDATE orders SET status = 'processing' WHERE id = 3;
  -- Oops — order 3 has a problem, rollback to the savepoint
  ROLLBACK TO SAVEPOINT after_order_2;
  -- Order 1 and 2 are processing, order 3 is still 'new'
COMMIT;

SELECT * FROM orders ORDER BY id;
